export default function FinalResults({ results }) {
  const [user, setUser] = useState(false);
  const [savedResults, setSavedResults] = useState(
    JSON.parse(localStorage.getItem("savedResults")) || []
  );
  const [type, setType] = useState("");
  const [articles, setArticles] = useState([]);
  const location = useLocation();

  // =========================
  // ტიპის გამოთვლა
  // =========================
  useEffect(() => {
    if (localStorage.getItem("auth_token")) setUser(true);

    let calculated =
      (results?.EI || "") +
      (results?.SN || "") +
      (results?.TF || "") +
      (results?.JP || "");

    if (!calculated || calculated.length !== 4) {
      const params = new URLSearchParams(location.search);
      calculated = params.get("type") || "";
    }

    if (!calculated || calculated.length !== 4) {
      calculated = localStorage.getItem("pendingResult") || "";
    }

    if (calculated.length === 4) {
      const finalType = calculated.toUpperCase();
      setType(finalType);
      localStorage.setItem("pendingResult", finalType);
    }
  }, [results, location]);

  // =========================
  // 🔥 AUTO SAVE MBTI (MongoDB)
  // =========================
  useEffect(() => {
    const autoSaveMBTI = async () => {
      if (!type) return;

      const token = localStorage.getItem("auth_token");
      if (!token) return;

      try {
        const res = await fetch("http://localhost:5000/api/user/mbti", {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`
          },
          body: JSON.stringify({ mbtiType: type })
        });

        if (!res.ok) throw new Error("Auto save failed");

        localStorage.setItem("savedResults", JSON.stringify([type]));
        setSavedResults([type]);

        console.log("✅ MBTI auto-saved:", type);

      } catch (err) {
        console.error("❌ Auto save error:", err);
      }
    };

    autoSaveMBTI();
  }, [type]);

  // =========================
  // სტატიები
  // =========================
  useEffect(() => {
    if (!type) return;

    fetch(`http://localhost:5000/api/articles?type=${type}`)
      .then(res => res.json())
      .then(data => setArticles(data || []))
      .catch(() => setArticles([]));
  }, [type]);

  if (!type) return <p>Loading...</p>;

  return (
    <div className="result-layout">
      <div className="register-page">
        <div className="register-card">

          {user && (
            <img
              src={savedResults.includes(type) ? "/save1.png" : "/save.png"}
              className="save-icon-result"
              alt="save"
            />
          )}

          <img
            className="result-image"
            src={`http://localhost:5000/images/${type}.png`}
            alt={type}
          />

          <h2 className="register-title">{type}</h2>

          <p className="register-description">
            {typeDescriptions[type]}
          </p>

          {!user && (
            <p className="register-text">
              მონაცემების შესანახად{" "}
              <Link
                to="/register"
                className="register-link"
                onClick={() => localStorage.setItem("pendingResult", type)}
              >
                გაიარე რეგისტრაცია
              </Link>
            </p>
          )}
        </div>
      </div>

      {articles.length > 0 && (
        <div className="articles-sidebar">
          <h3 className="sidebar-title">
            უკეთ გაიცანი შენი ფსიქოტიპი
          </h3>

          {articles.map(a => (
            <Link
              key={a.slug}
              to={`/articles/${a.slug}`}
              className="article-card"
            >
              <img
                className="article-thumb"
                alt={a.title}
                src={
                  a.image
                    ? `http://localhost:5000${a.image}`
                    : "http://localhost:5000/images/default.jpg"
                }
              />
              <div className="article-info">
                <b>{a.title}</b>
                <p>{a.excerpt}</p>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
